code.C:
#include <stdio.h>
int main() {
    char s[101];
    scanf("%s", s);
    int count = 0;
    for (int i = 0; s[i]; i++) {
        if (s[i] == 'H') count++;
    }
    printf("%d\n", count);
    return 0;
}

